<template>
  <div>
    <loading :active.sync="isLoading">
      <div class="loadingio-spinner-spin-ur5grgaunp">
        <div class="ldio-dwsbgiuamos">
          <div><div></div></div>
          <div><div></div></div>
          <div><div></div></div>
          <div><div></div></div>
          <div><div></div></div>
          <div><div></div></div>
          <div><div></div></div>
          <div><div></div></div>
        </div>
      </div>
    </loading>
    <div>
      <div class="float-left">
        <h4 class="my-3 font-weight-bold">
          <i aria-hidden="true" class="fa fa-list-ol"></i>
          訂單管理
        </h4>
      </div>
    </div>
    <table class="table table-striped table-bordered mt-4 text-dark">
      <thead>
        <tr>
          <th scope="col" width="180">訂單ID</th>
          <th scope="col" width="120">訂單成立時間</th>
          <th scope="col" width="180">用戶信箱</th>
          <th scope="col">購買款項</th>
          <th scope="col" width="100">應付金額</th>
          <th scope="col" width="100">付款狀態</th>
        </tr>
      </thead>
      <tbody>
        <tr v-for="item in orders" :key="item.id">
          <td>{{ item.id }}</td>
          <td scope="row">
            {{ new Date(item.create_at * 1000).toLocaleDateString() }}
          </td>
          <td>{{ item.user.email }}</td>
          <td>
            <div v-for="product in item.products" :key="product.id">
              {{
                `商品名稱：${product.product.title} 數量：${product.qty}/${product.product.unit}`
              }}
              <br />
            </div>
          </td>
          <td class="text-right">{{ item.total | numFormat | dollarSign }}</td>
          <td class="font-weight-bold">
            <span v-if="item.is_paid" class="text-success">已付款</span>
            <span v-else class="text-danger">未付款</span>
          </td>
        </tr>
      </tbody>
    </table>
    <Pagination :pages="pagination" @event="getOrders"></Pagination>
  </div>
</template>

<script>
import $ from "jquery";
import Pagination from "../Pagination";

export default {
  data() {
    return {
      orders: [],
      pagination: {},
      isLoading: false,
    };
  },
  methods: {
    getOrders(page = 1) {
      const vm = this;
      vm.isLoading = true;
      const api = `${process.env.APIPATH}api/${process.env.MYPATH}/admin/orders?page=${page}`;
      this.$http.get(api).then((res) => {
        vm.isLoading = false;
        if (res.data.success) {
          vm.orders = res.data.orders;
          vm.pagination = res.data.pagination;
        } else {
          vm.$bus.$emit("message:push", res.data.message, "danger");
        }
        console.log(res);
      });
    },
  },
  created() {
    this.getOrders();
  },
  components: {
    Pagination,
  },
};
</script>



